#include <bits/stdc++.h>
using namespace std;
int v,n,c,k[10004],m[10004],dp[10004];
int main(){
    scanf("%d%d%d",&v,&n,&c);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&k[i],&m[i]);
    for(int i=1;i<=n;i++)
        for(int j=c;j>=0;j--)
            if(j>=m[i])
                dp[j]=max(dp[j],dp[j-m[i]]+k[i]);
    for(int i=0;i<=c;i++)
        if(dp[i]>=v){
            cout<<c-i;
            return 0;
        }
    cout<<"Impossible";
    return 0;
}
